import sys

def compute_lps(pattern):
    lps = [0] * len(pattern)
    length = 0
    i = 1
    while i < len(pattern):
        if pattern[i] == pattern[length]:
            length += 1
            lps[i] = length
            i += 1
        else:
            if length != 0:
                length = lps[length - 1]
            else:
                lps[i] = 0
                i += 1
    return lps

def shortest_palindrome(s):
    rev = s[::-1]
    combined = rev + '#' + s
    lps = compute_lps(combined)
    longest_palindromic_prefix_length = lps[-1]
    return s + rev[longest_palindromic_prefix_length:]

def main():
    s = sys.stdin.readline().strip()
    print(shortest_palindrome(s))

if __name__ == "__main__":
    main()
